-            {
-                e.Handled = true;
-                textBox.AppendText(Environment.NewLine);
-                textBox.CaretIndex = textBox.Text.Length;
-            }
-        }
-
-        private static void TextBox_OnPaste(object sender, DataObjectPastingEventArgs e)
